try:
    status
except NameError:
    status = "Succeeded"

entity_name = (entity_name or "").strip()
assert entity_name, "Missing required param: entity_name"

def _to_dict(x):
    """
    Parse runContextJson tolerating:
    - dict
    - JSON string
    - double escaped JSON string
    """
    if isinstance(x, dict):
        return x
    if not x:
        return {}
    try:
        return json.loads(x)
    except Exception:
        return json.loads(bytes(x, "utf-8").decode("unicode_escape"))


def _utc_now_iso():
    return datetime.datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%SZ")


def _utc_now_ts():
    return datetime.datetime.utcnow().strftime("%Y-%m-%d %H:%M:%S")
